def detect_anomalies(logs: List[Dict[str, Any]], threshold_percentile: float = 0.99) -> List[Dict[str, Any]]:
    times = sorted([log.get('response_time', 0) for log in logs])
    if not times:
        return []
    threshold = times[int(len(times) * threshold_percentile)]
    return [log for log in logs if log.get('response_time', 0) > threshold]
